messages.content:
RISKS:
[
 {
  "riskId": "risk.definition-scopedown.intelligent-subset-inflation",
  "title": "The €300M base counts the non-intelligent majority of a market the venture cannot sell into",
  "claim": "The venture sells intelligent rack PDUs, but tamBase anchors on Grand View's $2.81B 'rack PDU' figure — and Grand View itself states the NON-intelligent segment held the largest revenue share in 2025. IndexBox confirms the split is real by selling 'Rack PDUs' and 'Intelligent Rack PDUs' as separate EU reports. The scope-down chain carefully audited geography and FX but never audited product type: roughly half the €300M base is basic/metered units the product line does not address. TAM, SAM and YAM all inherit a ~2x product-scope inflation while the ledger label ('rack-PDU market, all segments/buyers') reads as if it were scope-matched.",
  "falsifier": "A scope-pure European source (IndexBox EU Intelligent Rack PDUs headline, or an Omdia segment table) showing intelligent/monitored/switched PDUs at ≥75% of European rack-PDU revenue — i.e., Europe's revenue mix is intelligent-dominated even if global unit mix is not."
 },
 {
  "riskId": "risk.definition-scopedown.europe-30pct-arithmetic-ghost",
  "title": "The 'Europe ≈ 30%' hop is an inserted number; two sourced regional shares imply Europe is ≤24%",
  "claim": "The single most load-bearing hop in tamBase — Europe's share of the global rack-PDU market — is stated by no source. Grand View publishes only NA = 38%; MarketIntelo puts Asia-Pacific at 38.2% and calls it the DOMINANT region. If both regional leaders hold ~38%, Europe plus rest-of-world share a ~24% residual, and Europe alone plausibly sits at 20–23%, not 30%. The 30% was inferred from NA's share alone, before the APAC datapoint existed in the corpus. A 7-point regional-share error moves the base ~23% by itself, and unlike the tornado's band it is a directional bias, not symmetric noise.",
  "falsifier": "A published regional revenue table for the rack-PDU category (Grand View regional chapter, IndexBox world-vs-EU headline pair, or Omdia) showing Europe at ≥28% of global revenue."
 },
 {
  "riskId": "risk.definition-scopedown.colo-denominator-geography-misallocation",
  "title": "Colo-only apportionment plants the flag in Germany/NL while 35–40% of PDU demand sits in non-colo load with a different country mix",
  "claim": "Every geo share divides colo MW by colo MW, but rack-PDU demand tracks TOTAL installed IT load — and the non-colo remainder is not distributed like colocation. Germany's installed load (BMWK >2,700MW) exceeds its colo figure by ~1,000MW, Switzerland is self-operation-heavy (installed-basis share 0.13 vs 0.08), and Poland's better-corroborated installed-load figure yields 0.10 vs 0.07. EUDCA confirms the gap is continental: colo+hyperscale is only about two-thirds of Europe's IT power. A venture that builds its Year-1 named-account plan on the colo-derived map will staff Frankfurt and Amsterdam while a third of the actual PDU spend — enterprise and self-operated halls in CH, PL, AT — never appears on its target list.",
  "falsifier": "A single-scope, single-source table of total installed IT load for all CE-7 countries (e.g., EUDCA country profiles) whose per-country shares match the current colo-based shares within ±3 percentage points."
 },
 {
  "riskId": "risk.definition-scopedown.stock-vs-flow-intensity-mismatch",
  "title": "tamBase apportions revenue by standing MW, but PDU revenue follows new-build flow — which is concentrating outside CE-7",
  "claim": "The CE-7 = 39.8%-of-Europe hop divides standing colocation stock by standing stock. But rack-PDU revenue is fit-out-driven: it is earned when MW are delivered or refreshed, not while they sit installed. CBRE shows the flow concentrating away from CE: 57% of 2025's 937MW of new European supply lands in FLAPD (of which only Frankfurt and Amsterdam are CE-7), 85% of take-up is FLAPD, London alone exceeds 1GW and is Europe's largest market, and double-digit growth in secondary markets is going to Milan and Madrid — not Warsaw or Vienna. If CE-7's share of European capacity ADDITIONS is meaningfully below its 39.8% share of stock, the €300M systematically overstates where 2026 PDU purchase orders will actually be written, even if every input number is individually correct.",
  "falsifier": "CBRE's 2025–26 delivery pipeline (or Statista's 2026-vintage country deltas) showing CE-7 capturing ≥38% of new European colocation MW delivered — i.e., flow share matching stock share."
 },
 {
  "riskId": "risk.definition-scopedown.band-top-contaminated-comparator",
  "title": "The €360M ceiling was set with the same contaminated-category trick it claimed to remove — the real base may sit above the band and the plan is sized for the wrong market",
  "claim": "Refinement cycle 1 lowered the band top from €495M to €360M by comparing the BIS ceiling's 21% growth against a '10–12% intelligent-PDU CAGR (IndexBox)'. But that 10–12% figure comes from IndexBox's €8.5–9.5B EU 'Power and Cable Management' report — a category several times broader than rack PDUs — so the correction that purged one contaminated number imported another. Meanwhile Germany alone is forecast at $509.6M in a PDU category by 2031, already exceeding the entire CE-7 base, and the global anchors span $1.7–3.94B, a 2.3x spread wider than the band. If the true CE base sits at €400M+, the failure mode is not embarrassment — it is a Year-1 plan whose certification scope, channel headcount, and manufacturing commitments were sized for €165M of SAM while incumbents scale into the €80–120M the model never showed the board.",
  "falsifier": "The IndexBox EU Rack PDUs report headline (once purchased) landing at or below €360M for the 2025/2026 EU base, confirming the lowered ceiling despite the contaminated comparator."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
